const express = require('express');
const path = require('path');
const app = express();

app.use('/assets', express.static(path.join(__dirname, 'public'), {
  maxAge: '7d',
  immutable: false
}));

app.get('/', (req, res) => res.sendFile(path.join(__dirname, 'public', 'index.html')));
